import { Box } from '@otovo/rainbow';
import { contractPrerequisiteEnum } from '@otovo/shared/cloudEnums';
import Link from '@otovo/shared/components/RainbowLinkLegacy/RainbowLinkLegacy';
import {
  ContractPayloadType,
  ContractValidationErrorsType,
  useContractSigner,
} from '@otovo/shared/hooks/useContractSigner';
import useDebounce from '@otovo/shared/hooks/useDebounce';
import ArrowLeftSVG from '@otovo/shared/images/icons/arrow-left.svg';
import { Cloud$Offer } from '@otovo/shared/types/cloudApi';
import {
  Cloud$PurchaseModelCode,
  Cloud$SigningOption,
} from '@otovo/shared/types/cloudEnums';
import { useEffect, useState } from 'react';
import { FormattedMessage as T } from 'react-intl';
import PrerequisitesSection from './PrerequisitesSection';
import ReviewAndSignSection from './ReviewAndSignSection';
import { getUnfulfilled, isFulfilled } from './contractPrerequisiteUtils';
import m from './messages';
import usePreviewContract from './usePreviewContract';
import useValidateIban from './useValidateIban';

type Props = {
  offer: Cloud$Offer;
  purchaseModelCode: Cloud$PurchaseModelCode;
};

const ContractPage = ({ offer, purchaseModelCode }: Props) => {
  const contractPrerequisites = offer.contract_prerequisites[purchaseModelCode];
  const signingOptions = offer.signing_options;
  const [signUrl, setSignUrl] = useState('');
  const [signErrorCode, setSignErrorCode] = useState(null);
  const [signContractValidationError, setSignContractValidationError] =
    useState<ContractValidationErrorsType | undefined>();

  const { trigger, isMutating } = useContractSigner();
  const [cadastralId, setCadastralId] = useState('');
  const [iban, setIban] = useState('');
  const [bankIdentificationCode, setBankIdentificationCode] = useState('');

  const [bankDetailsConfirmed, setBankDetailsConfirmed] = useState(false);
  const [ssn, setSsn] = useState('');
  const [birthDate, setBirthDate] = useState('');
  const [documentID, setDocumentId] = useState('');
  const [birthPlace, setBirthPlace] = useState('');

  const [signButtonClicked, setSignButtonClicked] = useState(false);

  function createContractPayload(
    signingMethod: Cloud$SigningOption,
  ): ContractPayloadType {
    const payload: ContractPayloadType = {
      signing_method: signingMethod,
      offer_id: offer.id,
      purchase_model: purchaseModelCode,
    };

    if (ssn) {
      payload.ssn = ssn;
    }

    if (iban) {
      payload.iban = iban;
    }

    if (bankIdentificationCode) {
      payload.bank_identification_code = bankIdentificationCode;
    }

    if (cadastralId) {
      payload.cadastral_id = cadastralId;
    }

    if (birthDate) {
      payload.birth_date = birthDate;
    }

    if (birthPlace) {
      payload.birth_place = birthPlace;
    }

    if (documentID) {
      payload.document_id = documentID;
    }

    return payload;
  }

  function handleSignClick(signingMethod: Cloud$SigningOption) {
    trigger(createContractPayload(signingMethod), {
      onSuccess: (_signUrl: string | null) => {
        if (_signUrl) {
          setSignUrl(_signUrl);
        }
      },
      onError: (error) => {
        if ('error_code' in error) {
          setSignErrorCode(error.error_code);
        } else {
          setSignContractValidationError(error);
        }
      },
    });
  }

  function isFormCompleted() {
    const { BIRTH_DATE, BIRTH_PLACE, SSN, IBAN, CADASTRAL_ID } =
      contractPrerequisiteEnum;

    const ssnValid = !!ssn || isFulfilled(contractPrerequisites, SSN);
    const ibanValid =
      (!!iban && !!bankIdentificationCode && bankDetailsConfirmed) ||
      isFulfilled(contractPrerequisites, IBAN);
    const cadastralIdValid =
      !!cadastralId || isFulfilled(contractPrerequisites, CADASTRAL_ID);
    const birthDateValid =
      !!birthDate || isFulfilled(contractPrerequisites, BIRTH_DATE);
    const birthPlaceValid =
      !!birthPlace || isFulfilled(contractPrerequisites, BIRTH_PLACE);

    return (
      ssnValid &&
      ibanValid &&
      cadastralIdValid &&
      birthDateValid &&
      birthPlaceValid
    );
  }

  useEffect(() => {
    setBankDetailsConfirmed(false);
  }, [bankIdentificationCode, iban]);

  const debouncedIban = useDebounce(iban, 300);

  const { validationResult, isLoading: isValidatingIban } =
    useValidateIban(debouncedIban);

  const {
    previewContract,
    isGeneratingContract,
    previewContractValidationErrors,
  } = usePreviewContract();

  const handlePreviewClick = (signingOption: Cloud$SigningOption) => {
    previewContract(createContractPayload(signingOption));
  };

  useEffect(() => {
    if (!validationResult) {
      return;
    }
    if (validationResult.bic) {
      setBankIdentificationCode(validationResult.bic);
    }
  }, [isValidatingIban, validationResult]);

  useEffect(() => {
    setBankDetailsConfirmed(false);
  }, [iban, bankIdentificationCode]);

  useEffect(() => {
    if (signUrl) {
      window.location.href = signUrl;
    }
  }, [signUrl]);

  const validationErrors = {
    ...(signContractValidationError || {}),
    ...(previewContractValidationErrors || {}),
  };
  const hasValidationErrors = Object.keys(validationErrors).length > 0;

  const hideGoBackButton = signButtonClicked && !hasValidationErrors;
  const numUnfulfilledPrerequsites = getUnfulfilled(
    contractPrerequisites,
  ).length;
  const hasUnfulfilledPrerequisites = numUnfulfilledPrerequsites > 0;

  return (
    <Box
      maxWidth="18"
      mx="auto"
      px={{ s: 4, s3: 8, l2: 10 }}
      pt={{ s: 5, s3: 7 }}
      pb={{ s: 7, s3: 9 }}
    >
      <Link
        opacity={hideGoBackButton ? '0' : '1'}
        transition="opacity 150ms ease"
        display="inline-block"
        mb={{ s: 5, m3: 7 }}
        href={`/solar/offer/${offer.id}/configure`}
      >
        <Box display="flex" alignItems="center">
          <ArrowLeftSVG />
          <Box as="span" ml="2">
            <T {...m.backToOffer} />
          </Box>
        </Box>
      </Link>
      <Box
        display="grid"
        gridTemplateColumns={{
          s: 'repeat(1, minmax(0, 1fr))',
          m3: `repeat(${hasUnfulfilledPrerequisites ? 2 : 1}, minmax(0, 1fr))`,
        }}
        gridGap={{ s: 5, m3: 7 }}
      >
        {hasUnfulfilledPrerequisites && (
          <PrerequisitesSection
            onChangeDocumentId={setDocumentId}
            contractPrerequisites={contractPrerequisites}
            contractValidationErrors={validationErrors}
            isGeneratingContract={isGeneratingContract}
            onChangeBirthDate={setBirthDate}
            onChangeBirthPlace={setBirthPlace}
            onChangeCadastralId={setCadastralId}
            onChangeIban={setIban}
            onChangeBankIdentificationCode={setBankIdentificationCode}
            onChangeBankDetailsConfirmed={setBankDetailsConfirmed}
            onChangeSsn={setSsn}
            onPreviewClick={handlePreviewClick}
            signingOptions={signingOptions}
            bankIdentificationCode={bankIdentificationCode}
            ibanIsValid={validationResult?.valid}
            isValidatingIban={isValidatingIban}
            bankDetailsConfirmed={bankDetailsConfirmed}
          />
        )}
        <ReviewAndSignSection
          legalContact={offer.customer.legal_contact}
          isPosting={isMutating}
          isRedirecting={!!signUrl}
          onSignClick={(signingOption) => {
            handleSignClick(signingOption);
            setSignButtonClicked(true);
          }}
          onPreviewClick={handlePreviewClick}
          signErrorCode={signErrorCode}
          showSectionIndicator={hasUnfulfilledPrerequisites}
          isDisabled={!isFormCompleted()}
          isGeneratingContract={isGeneratingContract}
          signingOptions={signingOptions}
          contractPrerequisites={contractPrerequisites}
        />
      </Box>
    </Box>
  );
};

export default ContractPage;
