import { BodyM, Box, ErrorMessage, H2 } from '@otovo/rainbow';

import { signingOptions } from '@otovo/shared/cloudEnums';
import CheckmarkText from '@otovo/shared/components/CheckmarkText';
import Spinner from '@otovo/shared/components/LoadingScreens/Spinner';
import OtovoEmailLink from '@otovo/shared/components/OtovoEmailLink';
import Link from '@otovo/shared/components/RainbowLinkLegacy/RainbowLinkLegacy';
import { ContractErrorDetailsType } from '@otovo/shared/hooks/useContractSigner';
import ArrowDownCircleSVG from '@otovo/shared/images/icons/feather/arrow-down-circle.svg';
import dayjs from '@otovo/shared/lib/dayjs';
import { Cloud$LegalContact } from '@otovo/shared/types/cloudApi';
import {
  Cloud$ContractPrerequisite,
  Cloud$SigningOption,
} from '@otovo/shared/types/cloudEnums';
import { useEffect, useState } from 'react';
import { FormattedMessage as T } from 'react-intl';
import Section from './Section';
import SectionIndicator from './SectionIndicator';
import SignButton from './SignButton';
import { isAllPrerequisitesFulfilled } from './contractPrerequisiteUtils';
import m from './messages';

type Props = {
  contractPrerequisites: Cloud$ContractPrerequisite[];
  isDisabled: boolean;
  isGeneratingContract: boolean;
  isPosting: boolean;
  isRedirecting: boolean;
  legalContact: Cloud$LegalContact;
  onPreviewClick: (signingOption: Cloud$SigningOption) => void;
  onSignClick: (arg1: Cloud$SigningOption) => void;
  showSectionIndicator: boolean;
  signErrorCode: ContractErrorDetailsType['error_code'];
  signingOptions: Array<Cloud$SigningOption>;
};

const ReviewAndSignSection = ({
  contractPrerequisites,
  isDisabled,
  isGeneratingContract,
  isPosting,
  isRedirecting,
  legalContact,
  onPreviewClick,
  onSignClick,
  showSectionIndicator,
  signErrorCode,
  signingOptions: contractSigningOptions,
}: Props) => {
  const [smsAttempts, setSMSAttempts] = useState([]);

  const [sendingSMS, setSendingSMS] = useState(false);

  useEffect(() => {
    if (!isPosting && !signErrorCode && sendingSMS) {
      // We just finished sending SMS
      setSMSAttempts((prev) => [...prev, dayjs()]);
      setSendingSMS(false);
    }
  }, [isPosting, signErrorCode, sendingSMS]);

  const handleClick = (signingOption: Cloud$SigningOption) => {
    if (signingOption === signingOptions.SMS) {
      setSendingSMS(true);
    }

    onSignClick(signingOption);
  };

  return (
    <Section isDisabled={isDisabled}>
      {showSectionIndicator && (
        <SectionIndicator color={isDisabled ? 'grey_30' : undefined} mb="6">
          2
        </SectionIndicator>
      )}
      <H2
        mb="1"
        color={isDisabled ? 'grey_30' : undefined}
        transition="all 0.2s"
      >
        <T {...m.reviewAndSignTitle} />
      </H2>
      <BodyM
        mb="5"
        color={isDisabled ? 'grey_20' : undefined}
        transition="all 0.2s"
        maxWidth="measure"
      >
        <T {...m.reviewAndSignDescription} />
      </BodyM>
      {isGeneratingContract && (
        <Box display="flex" alignItems="center" mb="6">
          <Spinner size="w-16 h-16" className="mr-3" />
          <BodyM fontWeight="medium">
            <T {...m.previewContractLoading} />
          </BodyM>
        </Box>
      )}
      {isAllPrerequisitesFulfilled(contractPrerequisites) &&
        !isGeneratingContract && (
          <Link
            as="button"
            display="flex"
            alignItems="center"
            onClick={() => onPreviewClick(contractSigningOptions[0])}
            mb="6"
            transition="all 0.2s"
          >
            <Box
              as="span"
              fontSize="20px"
              display="inline-flex"
              alignItems="center"
              mr="2"
            >
              <ArrowDownCircleSVG />
            </Box>
            <T {...m.previewContract} />
          </Link>
        )}

      <div className="space-y-4">
        {contractSigningOptions.map((signingOption, index) => (
          <SignButton
            key={signingOption}
            disabled={isDisabled}
            isPosting={isPosting}
            isRedirecting={isRedirecting}
            variant={index === 0 ? 'blue' : 'secondary'}
            type={signingOption}
            onClick={handleClick}
          />
        ))}
      </div>

      <Box mt={5} maxWidth="measure">
        {smsAttempts.map((attempt) => (
          <CheckmarkText key={attempt.toISOString()}>
            <BodyM as="span" fontWeight="600">
              {attempt.format('HH:mm:ss')}
            </BodyM>{' '}
            <T
              {...m.smsSent}
              values={{
                phoneNumber: legalContact.profile.phone_number,
              }}
            />
          </CheckmarkText>
        ))}
        {!!signErrorCode && (
          <ErrorMessage mt="4">
            <T
              {...m.signFailed}
              values={{
                email: <OtovoEmailLink />,
              }}
            />
          </ErrorMessage>
        )}
      </Box>
    </Section>
  );
};

export default ReviewAndSignSection;
