You're right. Let's remove those redundant variables and fully integrate everything into the new `signingState` system:

```tsx
// ContractPage.tsx
type SigningState = {
  attemptedMethod: Cloud$SigningOption | null;
  isProcessing: boolean;
  hasBeenAttempted: boolean;
  error?: {
    errorCode?: string;
    validationErrors?: ContractValidationErrorsType;
  };
};

const ContractPage = ({ offer, purchaseModelCode }: Props) => {
  const [signUrl, setSignUrl] = useState('');
  const [signingState, setSigningState] = useState<SigningState>({
    attemptedMethod: null,
    isProcessing: false,
    hasBeenAttempted: false,
  });

  const { trigger } = useContractSigner();

  // Remove these now-redundant states
  // const [signErrorCode, setSignErrorCode] = useState(null);
  // const [signContractValidationError, setSignContractValidationError] = useState<ContractValidationErrorsType | undefined>();
  // const [signButtonClicked, setSignButtonClicked] = useState(false);

  function handleSignClick(signingMethod: Cloud$SigningOption) {
    setSigningState({
      attemptedMethod: signingMethod,
      isProcessing: true,
      hasBeenAttempted: true,
    });

    trigger(createContractPayload(signingMethod), {
      onSuccess: (_signUrl: string | null) => {
        if (_signUrl) {
          setSignUrl(_signUrl);
        } else {
          // Reset processing state but maintain hasBeenAttempted
          setSigningState((prev) => ({
            ...prev,
            attemptedMethod: null,
            isProcessing: false,
          }));
        }
      },
      onError: (error) => {
        setSigningState((prev) => ({
          attemptedMethod: null,
          isProcessing: false,
          hasBeenAttempted: prev.hasBeenAttempted,
          error: {
            errorCode: 'error_code' in error ? error.error_code : undefined,
            validationErrors: 'error_code' in error ? undefined : error,
          },
        }));
      },
    });
  }

  const validationErrors = {
    ...(signingState.error?.validationErrors || {}),
    ...(previewContractValidationErrors || {}),
  };
  const hasValidationErrors = Object.keys(validationErrors).length > 0;

  // Use signingState.hasBeenAttempted instead of signButtonClicked
  const hideGoBackButton = signingState.hasBeenAttempted && !hasValidationErrors;

  return (
    <Box
      maxWidth="18"
      mx="auto"
      px={{ s: 4, s3: 8, l2: 10 }}
      pt={{ s: 5, s3: 7 }}
      pb={{ s: 7, s3: 9 }}
    >
      <Link
        opacity={hideGoBackButton ? '0' : '1'}
        transition="opacity 150ms ease"
        display="inline-block"
        mb={{ s: 5, m3: 7 }}
        href={`/solar/offer/${offer.id}/configure`}
      >
        {/* ... */}
      </Link>

      {/* ... */}

      <ReviewAndSignSection
        legalContact={offer.customer.legal_contact}
        isDisabled={!isFormCompleted()}
        onSignClick={handleSignClick}
        onPreviewClick={handlePreviewClick}
        isGeneratingContract={isGeneratingContract}
        signingOptions={signingOptions}
        contractPrerequisites={contractPrerequisites}
        showSectionIndicator={hasUnfulfilledPrerequisites}
        signingState={signingState}
        isRedirecting={!!signUrl}
      />
    </Box>
  );
};
