  >(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/contracts/preview/`,
    downloadContract,
    {
      throwOnError: false,
    },
  );

  const wrappedTrigger = async (...args: Parameters<typeof trigger>) => {
    reset();
    return trigger(...args);
  };

  return {
    previewContract: wrappedTrigger,
    isGeneratingContract: isMutating,
    previewContractValidationErrors: 
      error && !('error_code' in error) 
        ? error 
        : undefined,
    previewContractErrorCode:
      error && 'error_code' in error
        ? error.error_code
        : undefined,
  };
}
